## Dumps the serialised text of a freshly-built AnimationTree so we can see
## exactly what property names Godot 4.3 uses.
extends SceneTree

func _init() -> void:
	# Build a BlendSpace2D with two points and print its property list
	var bs := AnimationNodeBlendSpace2D.new()
	var idle_anim := AnimationNodeAnimation.new()
	idle_anim.animation = &"idle"
	var east_anim := AnimationNodeAnimation.new()
	east_anim.animation = &"walk_east"

	bs.add_blend_point(idle_anim, Vector2(0, 0))
	bs.add_blend_point(east_anim, Vector2(1, 0))

	print("--- BlendSpace2D properties ---")
	for prop in bs.get_property_list():
		var val = bs.get(prop["name"])
		if val != null:
			print("  %s = %s" % [prop["name"], val])

	# Build a state machine with one transition and print it
	var sm := AnimationNodeStateMachine.new()
	sm.add_node(&"A", AnimationNodeAnimation.new())
	sm.add_node(&"B", AnimationNodeAnimation.new())
	var tr := AnimationNodeStateMachineTransition.new()
	tr.advance_condition = &"cond"
	sm.add_transition(&"A", &"B", tr)

	print("--- StateMachine properties ---")
	for prop in sm.get_property_list():
		var val = sm.get(prop["name"])
		if val != null:
			print("  %s = %s" % [prop["name"], val])

	# Save to a tres file so we can look at the text
	var bs2 := AnimationNodeBlendSpace2D.new()
	for i in range(5):
		var na := AnimationNodeAnimation.new()
		na.animation = &"idle"
		bs2.add_blend_point(na, Vector2(i, i))
	ResourceSaver.save(bs2, "res://tests/_bs2d_dump.tres")
	ResourceSaver.save(sm,  "res://tests/_sm_dump.tres")
	print("Saved dump files")
	quit(0)

